public class ArithmeticSequence {
    public static int nthTerm(int a, int d, int n) {
        // 'a' is first term  
        // 'd' is common difference  
        // 'n' is the nth term
        int result = a + (n - 1) * d;  
        return result; 
    }
    public static void main(String[] args){  
        // Sample usage
